import{_ as t,a,b as n,c as i,d as o,e as r}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as s,o as l,c as d,a2 as p}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"IP-geolocatie en gebruikersbeheer","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/Other/ip-geolocation-and-user-management.md","filePath":"nl-NL/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),c={name:"nl-NL/Other/ip-geolocation-and-user-management.md"};function g(b,e,h,u,k,v){return l(),d("div",null,[...e[0]||(e[0]=[p('<h1 id="ip-geolocatie-en-gebruikersbeheer" tabindex="-1">IP-geolocatie en gebruikersbeheer <a class="header-anchor" href="#ip-geolocatie-en-gebruikersbeheer" aria-label="Permalink to &quot;IP-geolocatie en gebruikersbeheer&quot;">​</a></h1><p>IP-geolocatie zet IP-adressen in uploaderrecords, loginapparaten en vergelijkbare logs om naar geschatte locaties.</p><p>Na configuratie kan het beheer duidelijker tonen waar uploads en toegang vandaan komen. Gebruikersbeheer laat je ook uploadtoegang voor verdachte IP-adressen blokkeren of herstellen.</p><h2 id="waar-je-dit-configureert" tabindex="-1">Waar je dit configureert <a class="header-anchor" href="#waar-je-dit-configureert" aria-label="Permalink to &quot;Waar je dit configureert&quot;">​</a></h2><p>Open:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+t+`" alt="IP-geolocatie" loading="lazy"></p><h2 id="beschikbare-instellingen" tabindex="-1">Beschikbare instellingen <a class="header-anchor" href="#beschikbare-instellingen" aria-label="Permalink to &quot;Beschikbare instellingen&quot;">​</a></h2><p>De nieuwere IP-geolocatieflow ondersteunt meerdere bronnen, in plaats van afhankelijk te zijn van één kaartdienst.</p><table tabindex="0"><thead><tr><th>Instelling</th><th>Doel</th></tr></thead><tbody><tr><td>IP-geolocatietaal</td><td>Kiest de weergavetaal, zoals Engels, Vereenvoudigd Chinees, Japans, Frans en andere talen.</td></tr><tr><td>MaxMind Account ID</td><td>MaxMind account-ID voor MaxMind GeoLite Web Service.</td></tr><tr><td>MaxMind License Key</td><td>MaxMind License Key.</td></tr><tr><td>Tencent Map Key</td><td>Tencent Location Service key. Handig voor Chinese adressen en IP&#39;s op het Chinese vasteland.</td></tr><tr><td>ipapi Key</td><td>APILayer ipapi key. Ondersteunt meertalige IP-geolocatie.</td></tr></tbody></table><p>Vul alleen de diensten in die je nodig hebt. Je hoeft niet elk veld te configureren.</p><p>Als je geen key invult, probeert ImgBed nog steeds ingebouwde gratis bronnen, maar stabiliteit, taalondersteuning en nauwkeurigheid kunnen lager zijn dan bij een eigen geconfigureerde dienst.</p><h2 id="aanbevolen-keuzes" tabindex="-1">Aanbevolen keuzes <a class="header-anchor" href="#aanbevolen-keuzes" aria-label="Permalink to &quot;Aanbevolen keuzes&quot;">​</a></h2><p>Als je vooral Chinese adressen nodig hebt:</p><ol><li>Zet de IP-geolocatietaal op Vereenvoudigd Chinees.</li><li>Configureer Tencent Map Key.</li><li>Voeg eventueel MaxMind of ipapi toe als fallback.</li></ol><p>Als je vooral Engels of meertalige adressen nodig hebt:</p><ol><li>Kies de gewenste taal.</li><li>Configureer MaxMind Account ID en License Key.</li><li>Voeg een ipapi Key toe als je betere meertalige resultaten wilt.</li></ol><h2 id="maxmind-instellen" tabindex="-1">MaxMind instellen <a class="header-anchor" href="#maxmind-instellen" aria-label="Permalink to &quot;MaxMind instellen&quot;">​</a></h2><p>MaxMind heeft nodig:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>Zoek de account-ID in het MaxMind-dashboard en genereer een License Key op de pagina License Keys.</p><p><img src="`+a+'" alt="MaxMind key-configuratie" loading="lazy"></p><p>Plak na het genereren Account ID en License Key in ImgBed en sla op.</p><p>Het gratis plan van MaxMind is geschikt voor dagelijks gebruik, maar heeft verzoeklimieten. Als de quota op is, probeert ImgBed andere beschikbare bronnen.</p><h2 id="ipapi-instellen" tabindex="-1">ipapi instellen <a class="header-anchor" href="#ipapi-instellen" aria-label="Permalink to &quot;ipapi instellen&quot;">​</a></h2><p>ipapi gebruikt een APILayer API Key.</p><p>Open de ipapi-console en kopieer de API Key die daar wordt getoond.</p><p><img src="'+n+'" alt="ipapi-configuratie" loading="lazy"></p><p>Plak deze in het veld <code>ipapi Key</code> in ImgBed en sla op.</p><p>ipapi ondersteunt meertalige IP-geolocatie en is handig wanneer je adressen in een gekozen taal wilt tonen. Ook het gratis plan heeft verzoeklimieten. Als de quota op raakt, probeert ImgBed andere beschikbare bronnen.</p><h2 id="tencent-map-key-instellen" tabindex="-1">Tencent Map Key instellen <a class="header-anchor" href="#tencent-map-key-instellen" aria-label="Permalink to &quot;Tencent Map Key instellen&quot;">​</a></h2><p>Tencent Map Key is nuttig voor Chinese adressen, vooral IP&#39;s op het Chinese vasteland.</p><p>Schakel bij het maken van een key in Tencent Location Service in:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>Plak na het aanmaken de key in <code>Tencent Map Key</code> en sla op.</p><p>Als je alleen basis-IP-geolocatie voor Chinese adressen nodig hebt, is Tencent Map Key genoeg om te beginnen.</p><h2 id="wat-je-controleert-in-gebruikersbeheer" tabindex="-1">Wat je controleert in Gebruikersbeheer <a class="header-anchor" href="#wat-je-controleert-in-gebruikersbeheer" aria-label="Permalink to &quot;Wat je controleert in Gebruikersbeheer&quot;">​</a></h2><p>Gebruikersbeheer is bereikbaar bovenaan het beheerpaneel.</p><p><img src="'+i+'" alt="Gebruikersbeheer" loading="lazy"></p><p>Gebruikersbeheer toont uploadactiviteit per IP:</p><table tabindex="0"><thead><tr><th>Veld</th><th>Beschrijving</th></tr></thead><tbody><tr><td>IP-bron</td><td>Bron-IP van de uploader.</td></tr><tr><td>Adres</td><td>Geschatte locatie die uit het IP is afgeleid.</td></tr><tr><td>Totale uploadgrootte</td><td>Totale bestandsgrootte geüpload door dit IP.</td></tr><tr><td>Aantal uploads</td><td>Aantal uploads vanaf dit IP.</td></tr><tr><td>Upload toegestaan</td><td>Aan betekent uploads toegestaan. Uit betekent uploads geblokkeerd.</td></tr></tbody></table><p>Klik op de pijl links om de lijst met door dat IP geüploade bestanden uit te klappen.</p><p>De bestandslijst toont bestandsnaam, preview, bestandsgrootte, moderatieresultaat, bestandsstatus en uploadtijd. Lijken uploads verdacht, klap dan eerst het IP uit, bekijk de bestanden en beslis daarna of verdere uploads moeten worden geblokkeerd.</p><p>Is een IP verdacht, zet <code>Upload allowed</code> uit. Toekomstige uploads vanaf dat IP worden geblokkeerd.</p><h2 id="zoeken-sorteren-en-geavanceerde-filters" tabindex="-1">Zoeken, sorteren en geavanceerde filters <a class="header-anchor" href="#zoeken-sorteren-en-geavanceerde-filters" aria-label="Permalink to &quot;Zoeken, sorteren en geavanceerde filters&quot;">​</a></h2><p>Bovenaan Gebruikersbeheer kun je zoeken op IP-bron of adres.</p><p>Sorteer op tijd, aantal uploads of totale uploadgrootte om recente uploaders, veeluploaders of IP&#39;s met veel gebruik te vinden.</p><p>Open geavanceerde filters voor dieper onderzoek.</p><p><img src="'+o+'" alt="Geavanceerde filters" loading="lazy"></p><p>Geavanceerde filters ondersteunen:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Gebruik</th></tr></thead><tbody><tr><td>Tijdsbereik</td><td>Toon IP&#39;s die in een gekozen periode bestanden hebben geüpload.</td></tr><tr><td>Toegangsstatus</td><td>Filter op normaal, geblokkeerd en vergelijkbare statussen.</td></tr><tr><td>Allow/block list</td><td>Filter op allowlist, blocklist of niet ingesteld.</td></tr><tr><td>Bestandstype</td><td>Toon IP&#39;s die afbeeldingen, video&#39;s, audio, documenten, code of andere bestanden hebben geüpload.</td></tr><tr><td>Bestandsgrootte</td><td>Filter op geüploade bestandsgrootte.</td></tr><tr><td>Leeftijdsrating</td><td>Filter op niet ingesteld, General, R12+, R16+, R18 en vergelijkbare ratings.</td></tr><tr><td>Bestandsstatus</td><td>Filter op huidige bestandsstatus om afwijkende bestanden te onderzoeken.</td></tr></tbody></table><p>Klik op <code>Apply Filters</code> om toe te passen. Gebruik <code>Reset</code> om terug te gaan naar alle gegevens.</p><h2 id="mobiele-weergave" tabindex="-1">Mobiele weergave <a class="header-anchor" href="#mobiele-weergave" aria-label="Permalink to &quot;Mobiele weergave&quot;">​</a></h2><p>Op mobiel schakelt Gebruikersbeheer over naar kaartweergave.</p><p><img src="'+r+`" alt="Mobiel gebruikersbeheer" loading="lazy"></p><p>Elke kaart toont IP, adres, totale uploadgrootte, aantal uploads en de schakelaar voor upload toegestaan. Je kunt gebruikers beheren zonder horizontaal door een tabel te scrollen.</p><h2 id="als-de-locatie-niet-klopt" tabindex="-1">Als de locatie niet klopt <a class="header-anchor" href="#als-de-locatie-niet-klopt" aria-label="Permalink to &quot;Als de locatie niet klopt&quot;">​</a></h2><p>IP-geolocatie is bij benadering. Het is geen precies straatadres.</p><p>Als een gebruiker via een proxy, datacenter, cloudserver of grensoverschrijdend netwerk werkt, kan de getoonde locatie verschillen van de werkelijke locatie.</p><p>Gebruik deze functie om herkomst grof te begrijpen, afwijkende uploads te vinden en blokkeerbeslissingen te ondersteunen. Behandel het niet als nauwkeurige tracking.</p><h2 id="veelvoorkomende-situaties" tabindex="-1">Veelvoorkomende situaties <a class="header-anchor" href="#veelvoorkomende-situaties" aria-label="Permalink to &quot;Veelvoorkomende situaties&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Situatie</th><th>Betekenis</th></tr></thead><tbody><tr><td>Adres is leeg</td><td>Het IP is mogelijk nog niet opgelost, of de huidige bron is tijdelijk niet beschikbaar.</td></tr><tr><td>Adrestaal is verkeerd</td><td>Controleer de IP-geolocatietaal en of een bron is ingesteld die die taal ondersteunt.</td></tr><tr><td>Adres toont een datacenter</td><td>Veel proxy&#39;s, cloudservers en crawlers verschijnen als datacenter- of ISP-adressen.</td></tr><tr><td>Aantal uploads is hoog</td><td>Bekijk dit IP zorgvuldig en blokkeer uploads indien nodig.</td></tr><tr><td>Totale uploadgrootte is groot</td><td>Sorteer of filter, klap het IP uit en inspecteer specifieke bestanden.</td></tr><tr><td>Herstellen na blokkeren</td><td>Zet <code>Upload allowed</code> weer aan.</td></tr></tbody></table><h2 id="snelle-flow" tabindex="-1">Snelle flow <a class="header-anchor" href="#snelle-flow" aria-label="Permalink to &quot;Snelle flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Open IP Geolocation in Other Settings</span></span>
<span class="line"><span>-&gt; Kies IP-geolocatietaal</span></span>
<span class="line"><span>-&gt; Vul MaxMind, Tencent Map of ipapi in waar nodig</span></span>
<span class="line"><span>-&gt; Sla instellingen op</span></span>
<span class="line"><span>-&gt; Open Gebruikersbeheer</span></span>
<span class="line"><span>-&gt; Controleer IP-bron, adres, totale uploadgrootte en aantal uploads</span></span>
<span class="line"><span>-&gt; Gebruik zoeken, sorteren of geavanceerde filters om afwijkende IP&#39;s te vinden</span></span>
<span class="line"><span>-&gt; Sta uploads toe of blokkeer ze waar nodig</span></span></code></pre></div>`,64)])])}const I=s(c,[["render",g]]);export{P as __pageData,I as default};
